1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases ---
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const out = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(out).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums per main item type (no modifiers, 0 years, first quote) ---
15	  // Plain item base premium + 10 G first-insurance + 5 G fee
16	  it.todo("plain sword (steel, enchantment 0) for new customer → premium 115 G (100 + 10 + 5)");
17	  it.todo("plain amulet for new customer → premium 71 G (60 + 6 first-insurance rounded up + 5)");
18	  it.todo("plain staff for new customer → premium 93 G (80 + 8 + 5)");
19	  it.todo("plain potion for new customer → premium 49 G (40 + 4 + 5)");
20	
21	  // --- Component pricing (runes/moonstones) ---
22	  it.todo("2 runes → base premium 50 G (no block)");
23	  it.todo("3 runes → base premium 60 G (block applies)");
24	  it.todo("4 runes → base premium 100 G (no block — block requires exactly 3)");
25	  it.todo("7 runes → base premium 175 G (3-block + 4 leftover at 25 G each)");
26	
27	  // --- 'Alike' components clarification (❓) ---
28	  it.todo("2 runes + 1 moonstone → base premium 75 G (no block: different types)");
29	  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");
30	
31	  // --- Modifiers in isolation (item-specific) ---
32	  it.todo("newcomer with a cursed sword (steel, enchantment 3) → premium 165 G");
33	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies (130 G + 5 fee + 13 first ins.)");
34	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
35	  it.todo("cursed sword with exactly enchantment 5 → both surcharges apply");
36	
37	  // --- Policy-wide modifiers ---
38	  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
39	  it.todo("first quote in scenario carries 10% first-insurance surcharge per item");
40	  it.todo("second quote in scenario gets 15% follow-up contract discount");
41	
42	  // --- Modifier scope on multi-item policies (❓) ---
43	  it.todo("cursed sword + plain amulet → 210 G before fee (item-specific surcharge applies only to cursed item)");
44	
45	  // --- Rounding in MHPCO's favor ---
46	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
47	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
48	  it.todo("intermediate amounts kept as fractions; only final is rounded");
49	
50	  // --- Integration examples ---
51	  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
52	  it.todo("long-standing customer's second contract (3 years, cursed sword enchantment 7) → premium 160 G");
53	
54	  // --- Claim processing: standard reimbursement ---
55	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 - 100 deductible)");
56	  it.todo("damage to a rune (value 250 G), damage 200 G → payout 100 G");
57	
58	  // --- Claim processing: enchantment threshold ---
59	  it.todo("dragon-material sword with exactly enchantment 8, damage 1000 G → payout 400 G (high-ench wins, then deductible)");
60	  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
61	  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon only: full minus deductible)");
62	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (high-ench: 50% then deductible)");
63	
64	  // --- Deductible per damage event ---
65	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible once per damaged item)");
66	
67	  // --- Multiple items of same type ---
68	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
69	  it.todo("two-sword policy: dragon attack with two sword damage entries → each treated separately with own deductible");
70	  it.todo("damages contain more entries of a type than policy covers → CLI exits non-zero");
71	
72	  // --- Cap exhaustion ---
73	  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
74	  it.todo("cursed sword (insurance value 1000 G) → cap 2000 G (modifiers do not raise cap)");
75	  it.todo("policy with sword + 3 runes → insurance sum 1750 G (block discount affects premium only)");
76	  it.todo("sword insured (cap 2000 G); two successive 1500 G claims → first 1400 G remaining 600 G; second 600 G remaining 0 G");
77	
78	  // --- Edge cases ---
79	  it.todo("quote includes unknown item type (e.g. 'broomstick') → CLI exits non-zero with stderr error, no results on stdout");
80	  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero with stderr error");
81	  it.todo("claim references damage entry with unknown item type → CLI exits non-zero with stderr error");
82	  it.todo("claim contains damage entry with negative amount → CLI exits non-zero with stderr error");
83	
84	  // --- End-to-end schema example ---
85	  it.todo("schema example: long-standing customer amulet quote + fire claim 200 G → premium and payout integers per schema");
86	});
